// Parse and validate the AI video script output.
const rawContent = $input.first().json?.message?.content
  || $input.first().json?.choices?.[0]?.message?.content
  || '';
const ctx = $('Execute Workflow Trigger').first().json;

const VALID_SOURCE_ROLES = ['primary', 'data', 'commentary'];

let video_script;
try {
  const cleaned = rawContent.replace(/^```[a-z]*\n?|\n?```$/g, '').trim();
  video_script = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse video script JSON for ${ctx.topic_slug}/${ctx.date_key}: ${e.message}`);
}

// Validate required fields
if (!video_script.intro || video_script.intro.length < 30) {
  throw new Error('Video script missing or too short intro');
}
if (!Array.isArray(video_script.segments) || video_script.segments.length < 2) {
  throw new Error('Video script missing segments (minimum 2 required)');
}
if (!video_script.outro || video_script.outro.length < 30) {
  throw new Error('Video script missing or too short outro');
}
if (typeof video_script.total_duration_seconds !== 'number') {
  // Estimate from segment durations
  const segDuration = video_script.segments.reduce((s, seg) => s + (seg.duration_seconds || 30), 0);
  video_script.total_duration_seconds = segDuration + 30 + 20; // + intro + outro estimates
}

// Helper: normalize a source reference array
function normalizeSources(arr, maxItems) {
  if (!Array.isArray(arr) || arr.length === 0) return null;
  const normalized = arr.slice(0, maxItems).map(s => ({
    source_name: String(s.source_name || '').slice(0, 200),
    source_url: s.source_url ? String(s.source_url).slice(0, 2000) : null,
    source_role: VALID_SOURCE_ROLES.includes(s.source_role) ? s.source_role : null
  })).filter(s => s.source_name.length > 0);
  return normalized.length > 0 ? normalized : null;
}

// Clamp and trim
video_script.intro = String(video_script.intro).slice(0, 500);
video_script.outro = String(video_script.outro).slice(0, 400);
video_script.total_duration_seconds = Math.min(600, Math.max(60, Math.round(video_script.total_duration_seconds)));
video_script.segments = video_script.segments.slice(0, 5).map(s => ({
  title: String(s.title || '').slice(0, 100),
  script: String(s.script || '').slice(0, 1500),
  duration_seconds: Math.min(120, Math.max(15, Math.round(s.duration_seconds || 30))),
  sources: normalizeSources(s.sources, 5)
}));
video_script.call_to_action = video_script.call_to_action
  ? String(video_script.call_to_action).slice(0, 200)
  : null;

return [{ json: { ...ctx, video_script } }];
